import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { AuthService } from '../../core/services/auth.service';
import { Course } from '../../core/models';

/**
 * LearnLoop course detail — public. Shows ordered modules → lessons + quizzes,
 * an enroll button, and (when enrolled) a progress bar. Loads via
 * ApiService.getCourse(id) in ngOnInit().
 */
@Component({
  selector: 'app-course-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './course-detail.component.html',
  styleUrl: './course-detail.component.css',
})
export class CourseDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly enrolling = signal(false);

  readonly course = signal<Course | null>({
    id: 'c1',
    title: 'Intro to Web Development',
    description:
      'Build your first web pages from scratch. Learn HTML structure, CSS styling, and the fundamentals of how the browser renders your work.',
    enrolled: false,
    progressPct: 40,
    modules: [
      {
        id: 'm1',
        courseId: 'c1',
        order: 1,
        title: 'HTML Basics',
        lessons: [
          { id: 'l1', moduleId: 'm1', order: 1, title: 'What is HTML?', content: '', viewed: true },
          { id: 'l2', moduleId: 'm1', order: 2, title: 'Elements & Tags', content: '', viewed: true },
        ],
        quizzes: [],
      },
      {
        id: 'm2',
        courseId: 'c1',
        order: 2,
        title: 'Styling with CSS',
        lessons: [
          { id: 'l3', moduleId: 'm2', order: 1, title: 'Selectors & Properties', content: '', viewed: false },
        ],
        quizzes: [
          { id: 'q1', moduleId: 'm2', title: 'CSS Fundamentals Quiz', attemptLimit: 1 },
        ],
      },
    ],
  });

  courseId = '';

  constructor(
    private api: ApiService,
    private route: ActivatedRoute,
    public auth: AuthService,
  ) {}

  ngOnInit(): void {
    this.courseId = this.route.snapshot.paramMap.get('id') ?? '';
    this.loading.set(true);
    this.error.set(null);
    this.api.getCourse(this.courseId).subscribe({
      next: (course) => {
        this.course.set(course);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load this course. Please try again.');
        this.loading.set(false);
      },
    });
  }

  enroll(): void {
    if (!this.auth.isLoggedIn()) return;
    this.enrolling.set(true);
    this.api.enroll(this.courseId).subscribe({
      next: () => {
        const c = this.course();
        if (c) this.course.set({ ...c, enrolled: true });
        this.enrolling.set(false);
      },
      error: () => this.enrolling.set(false),
    });
  }
}
